changeSet.sql:
DO $$
DECLARE
    org_id bigint;
    demo_site_id bigint;
    qa_dept_id bigint;
    mfg_dept_id bigint;
    admin_id bigint;
    qa_user_id bigint;
    author_user_id bigint;
    operator_user_id bigint;
    qa_role_id bigint;
    author_role_id bigint;
    operator_role_id bigint;
    current_year int := EXTRACT(YEAR FROM now() AT TIME ZONE 'UTC')::int;
    product_tablet_id bigint;
    product_syrup_id bigint;
    material_api_id bigint;
    material_pack_id bigint;
    doc_sop_id bigint;
    doc_batch_form_id bigint;
    capa_label_id bigint;
    capa_training_id bigint;
    batch_tablet_id bigint;
    audit_gmp_id bigint;
    supplier_api_id bigint;
    equipment_balance_id bigint;
    risk_mixup_id bigint;
    oos_assay_id bigint;
    nc_pack_id bigint;
    mr_q2_id bigint;
BEGIN
    SELECT id INTO org_id FROM organizations WHERE code = 'DEFAULT';
    IF org_id IS NULL THEN
        INSERT INTO organizations (code, name, legal_name, primary_contact_email, status, version, created_at, updated_at)
        VALUES ('DEFAULT', 'Default Organization', 'Default Organization', 'admin@eqms.local', 'active', 0, now(), now())
        RETURNING id INTO org_id;
    END IF;

    INSERT INTO sites (code, name, timezone, organization_id, version, created_at, updated_at)
    VALUES ('NAIROBI-GMP', 'Nairobi GMP Site', 'Africa/Nairobi', org_id, 0, now(), now())
    ON CONFLICT (code) DO UPDATE SET name = EXCLUDED.name, timezone = EXCLUDED.timezone, updated_at = now()
    RETURNING id INTO demo_site_id;

    INSERT INTO departments (site_id, code, name, organization_id, version, created_at, updated_at)
    VALUES (demo_site_id, 'QA', 'Quality Assurance', org_id, 0, now(), now())
    ON CONFLICT (site_id, code) DO UPDATE SET name = EXCLUDED.name, updated_at = now()
    RETURNING id INTO qa_dept_id;

    INSERT INTO departments (site_id, code, name, organization_id, version, created_at, updated_at)
    VALUES (demo_site_id, 'MFG', 'Manufacturing', org_id, 0, now(), now())
    ON CONFLICT (site_id, code) DO UPDATE SET name = EXCLUDED.name, updated_at = now()
    RETURNING id INTO mfg_dept_id;

    SELECT id INTO admin_id FROM users WHERE email = 'admin@eqms.local';
    SELECT id INTO qa_role_id FROM roles WHERE name = 'QA_MANAGER';
    SELECT id INTO author_role_id FROM roles WHERE name = 'AUTHOR';
    SELECT id INTO operator_role_id FROM roles WHERE name = 'OPERATOR';

    INSERT INTO users (email, username, full_name, password_hash, mfa_enabled, status, site_id, department_id, organization_id, version, created_at, updated_at)
    VALUES ('demo.qa@eqms.local', 'demo.qa', 'Demo QA Manager', '$argon2id$v=19$m=16384,t=2,p=1$/VVmikRrEgFe6SyOgqjPEw$vviJ/Wa0RGJYH6olPVu9REIALotPJxiVAVE9Y/c2evo', false, 'ACTIVE', demo_site_id, qa_dept_id, org_id, 0, now(), now())
    ON CONFLICT (email) DO UPDATE SET full_name = EXCLUDED.full_name, site_id = EXCLUDED.site_id, department_id = EXCLUDED.department_id, organization_id = EXCLUDED.organization_id, updated_at = now()
    RETURNING id INTO qa_user_id;

    INSERT INTO users (email, username, full_name, password_hash, mfa_enabled, status, site_id, department_id, organization_id, version, created_at, updated_at)
    VALUES ('demo.author@eqms.local', 'demo.author', 'Demo Document Author', '$argon2id$v=19$m=16384,t=2,p=1$/VVmikRrEgFe6SyOgqjPEw$vviJ/Wa0RGJYH6olPVu9REIALotPJxiVAVE9Y/c2evo', false, 'ACTIVE', demo_site_id, qa_dept_id, org_id, 0, now(), now())
    ON CONFLICT (email) DO UPDATE SET full_name = EXCLUDED.full_name, site_id = EXCLUDED.site_id, department_id = EXCLUDED.department_id, organization_id = EXCLUDED.organization_id, updated_at = now()
    RETURNING id INTO author_user_id;

    INSERT INTO users (email, username, full_name, password_hash, mfa_enabled, status, site_id, department_id, organization_id, version, created_at, updated_at)
    VALUES ('demo.operator@eqms.local', 'demo.operator', 'Demo Manufacturing Operator', '$argon2id$v=19$m=16384,t=2,p=1$/VVmikRrEgFe6SyOgqjPEw$vviJ/Wa0RGJYH6olPVu9REIALotPJxiVAVE9Y/c2evo', false, 'ACTIVE', demo_site_id, mfg_dept_id, org_id, 0, now(), now())
    ON CONFLICT (email) DO UPDATE SET full_name = EXCLUDED.full_name, site_id = EXCLUDED.site_id, department_id = EXCLUDED.department_id, organization_id = EXCLUDED.organization_id, updated_at = now()
    RETURNING id INTO operator_user_id;

    INSERT INTO user_roles (user_id, role_id, granted_at, organization_id, version, created_at, updated_at)
    SELECT qa_user_id, qa_role_id, now(), org_id, 0, now(), now()
    WHERE qa_role_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM user_roles WHERE user_id = qa_user_id AND role_id = qa_role_id);

    INSERT INTO user_roles (user_id, role_id, granted_at, organization_id, version, created_at, updated_at)
    SELECT author_user_id, author_role_id, now(), org_id, 0, now(), now()
    WHERE author_role_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM user_roles WHERE user_id = author_user_id AND role_id = author_role_id);

    INSERT INTO user_roles (user_id, role_id, granted_at, organization_id, version, created_at, updated_at)
    SELECT operator_user_id, operator_role_id, now(), org_id, 0, now(), now()
    WHERE operator_role_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM user_roles WHERE user_id = operator_user_id AND role_id = operator_role_id);

    IF admin_id IS NULL THEN
        admin_id := qa_user_id;
    ELSE
        UPDATE users u SET site_id = COALESCE(u.site_id, (SELECT s.id FROM sites s WHERE s.code = 'NAIROBI-GMP')),
            department_id = COALESCE(u.department_id, qa_dept_id),
            organization_id = COALESCE(u.organization_id, org_id),
            updated_at = now()
        WHERE id = admin_id;
    END IF;

    -- Product and material master data used by downstream manufacturing, complaint, OOS, and NC rows.
    INSERT INTO products (product_code, name, description, dosage_form, strength, registration_number, status, submitted_by, organization_id, version, created_at, created_by, updated_at, updated_by)
    VALUES
      ('PROD-' || current_year || '-001', 'Paracetamol 500 mg Tablets', 'Immediate-release analgesic tablet for demo workflows.', 'TABLET', '500 mg', 'KE-DEMO-PARA-500', 'ACTIVE', qa_user_id, org_id, 0, now() - interval '35 days', author_user_id, now() - interval '3 days', qa_user_id),
      ('PROD-' || current_year || '-002', 'Cetirizine 5 mg/5 mL Syrup', 'Antihistamine syrup awaiting quality approval.', 'SYRUP', '5 mg/5 mL', 'KE-DEMO-CET-005', 'PENDING_APPROVAL', author_user_id, org_id, 1, now() - interval '9 days', author_user_id, now() - interval '1 day', author_user_id)
    ON CONFLICT (product_code) DO UPDATE SET name = EXCLUDED.name, status = EXCLUDED.status, updated_at = now();
    SELECT id INTO product_tablet_id FROM products WHERE product_code = 'PROD-' || current_year || '-001';
    SELECT id INTO product_syrup_id FROM products WHERE product_code = 'PROD-' || current_year || '-002';

    INSERT INTO materials (material_code, name, description, material_type, unit_of_measure, specification, status, submitted_by, organization_id, version, created_at, created_by, updated_at, updated_by)
    VALUES
      ('MAT-' || current_year || '-001', 'Paracetamol API', 'Qualified active ingredient for tablet manufacture.', 'ACTIVE_INGREDIENT', 'KG', 'Assay 98.0-102.0%; water NMT 0.5%.', 'APPROVED', qa_user_id, org_id, 1, now() - interval '40 days', author_user_id, now() - interval '8 days', qa_user_id),
      ('MAT-' || current_year || '-002', 'PVC/Alu Blister Foil', 'Primary packaging material under supplier verification.', 'PACKAGING', 'UNIT', 'Print registration and seal integrity per approved spec.', 'PENDING_APPROVAL', author_user_id, org_id, 0, now() - interval '6 days', author_user_id, now() - interval '1 day', author_user_id),
      ('MAT-' || current_year || '-003', 'Purified Water', 'Utility material temporarily on hold pending conductivity review.', 'RAW_MATERIAL', 'L', 'Meets pharmacopeial purified water specification.', 'ON_HOLD', qa_user_id, org_id, 2, now() - interval '22 days', qa_user_id, now() - interval '2 days', qa_user_id)
    ON CONFLICT (material_code) DO UPDATE SET name = EXCLUDED.name, status = EXCLUDED.status, updated_at = now();
    SELECT id INTO material_api_id FROM materials WHERE material_code = 'MAT-' || current_year || '-001';
    SELECT id INTO material_pack_id FROM materials WHERE material_code = 'MAT-' || current_year || '-002';

    -- Document Control.
    INSERT INTO documents (document_number, title, document_type, status, content, major_version, effective_date, next_review_date, review_period_months, submitted_by, organization_id, version, created_at, created_by, updated_at, updated_by)
    VALUES
      ('SOP-' || current_year || '-001', 'Batch Manufacturing Record Review SOP', 'SOP', 'EFFECTIVE', 'Defines QA review, reconciliation, and batch release checks.', 2, now() - interval '25 days', now() + interval '11 months', 12, qa_user_id, org_id, 2, now() - interval '70 days', author_user_id, now() - interval '25 days', qa_user_id),
      ('FORM-' || current_year || '-001', 'Line Clearance Checklist', 'FORM', 'PENDING_APPROVAL', 'Checklist for pre-production line clearance and label verification.', 1, null, now() + interval '12 months', 12, author_user_id, org_id, 1, now() - interval '8 days', author_user_id, now() - interval '1 day', author_user_id),
      ('WI-' || current_year || '-001', 'HPLC Assay Sample Preparation', 'WORK_INSTRUCTION', 'UNDER_REVIEW', 'Draft sample preparation steps for assay testing.', 1, null, now() + interval '12 months', 12, author_user_id, org_id, 0, now() - interval '5 days', author_user_id, now() - interval '1 day', author_user_id)
    ON CONFLICT (document_number) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, updated_at = now();
    SELECT id INTO doc_sop_id FROM documents WHERE document_number = 'SOP-' || current_year || '-001';
    SELECT id INTO doc_batch_form_id FROM documents WHERE document_number = 'FORM-' || current_year || '-001';

    INSERT INTO document_versions (document_id, major_version, version_label, status, title, content, change_notes, created_by, created_by_name, created_at, organization_id)
    SELECT doc_sop_id, 2, 'v2.0', 'EFFECTIVE', 'Batch Manufacturing Record Review SOP', 'Defines QA review, reconciliation, and batch release checks.', 'Demo effective version.', qa_user_id, 'Demo QA Manager', now() - interval '25 days', org_id
    WHERE NOT EXISTS (SELECT 1 FROM document_versions WHERE document_id = doc_sop_id AND version_label = 'v2.0');

    INSERT INTO document_read_assignments (document_id, assigned_to, assigned_at, assigned_by, acknowledged_at, organization_id, version, created_at, created_by, updated_at, updated_by)
    SELECT doc_sop_id, operator_user_id, now() - interval '12 days', qa_user_id, now() - interval '10 days', org_id, 0, now() - interval '12 days', qa_user_id, now() - interval '10 days', operator_user_id
    WHERE NOT EXISTS (SELECT 1 FROM document_read_assignments WHERE document_id = doc_sop_id AND assigned_to = operator_user_id);

    -- Change Control.
    INSERT INTO change_controls (change_number, title, description, change_type, status, justification, effectiveness_check_required, target_implementation_date, implemented_date, closed_date, submitted_by, organization_id, version, created_at, created_by, updated_at, updated_by)
    VALUES
      ('CC-' || current_year || '-001', 'Revise packaging line clearance flow', 'Add barcode verification before first print approval.', 'MAJOR', 'PENDING_APPROVAL', 'Reduces packaging mix-up risk.', true, now() + interval '21 days', null, null, author_user_id, org_id, 1, now() - interval '14 days', author_user_id, now() - interval '1 day', author_user_id),
      ('CC-' || current_year || '-002', 'Update HPLC column supplier', 'Introduce qualified alternate column supplier.', 'MINOR', 'IN_IMPLEMENTATION', 'Approved alternate source improves continuity.', false, now() + interval '15 days', null, null, qa_user_id, org_id, 2, now() - interval '24 days', qa_user_id, now() - interval '2 days', qa_user_id),
      ('CC-' || current_year || '-003', 'Warehouse label printer replacement', 'Replace obsolete label printer and verify templates.', 'MINOR', 'CLOSED', 'Printer reached end of service life.', true, now() - interval '20 days', now() - interval '12 days', now() - interval '5 days', qa_user_id, org_id, 4, now() - interval '50 days', qa_user_id, now() - interval '5 days', qa_user_id)
    ON CONFLICT (change_number) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, updated_at = now();

    -- CAPA.
    INSERT INTO capas (capa_number, title, description, source, root_cause, status, effectiveness_check_required, effectiveness_check_result, due_date, closed_date, submitted_by, organization_id, version, created_at, created_by, updated_at, updated_by)
    VALUES
      ('CAPA-' || current_year || '-001', 'Prevent label roll mix-up during packaging', 'Wrong label roll staged during line clearance.', 'DEVIATION', 'Similar label roll storage bins and incomplete second-person verification.', 'IN_PROGRESS', true, null, now() + interval '18 days', null, author_user_id, org_id, 3, now() - interval '28 days', author_user_id, now() - interval '2 days', qa_user_id),
      ('CAPA-' || current_year || '-002', 'Improve OOS sample reconciliation', 'Retain sample reconciliation gaps found during lab review.', 'OOS', 'Manual reconciliation step was not consistently documented.', 'PENDING_APPROVAL', true, null, now() + interval '30 days', null, author_user_id, org_id, 1, now() - interval '12 days', author_user_id, now() - interval '1 day', author_user_id),
      ('CAPA-' || current_year || '-003', 'Supplier COA verification checklist', 'Supplier audit finding on incomplete COA review evidence.', 'SUPPLIER', 'Incoming QC checklist did not require independent COA trace check.', 'CLOSED', true, 'Three incoming lots reviewed with complete COA trace evidence.', now() - interval '2 days', now() - interval '1 day', qa_user_id, org_id, 5, now() - interval '65 days', qa_user_id, now() - interval '1 day', qa_user_id)
    ON CONFLICT (capa_number) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, updated_at = now();
    SELECT id INTO capa_label_id FROM capas WHERE capa_number = 'CAPA-' || current_year || '-001';
    SELECT id INTO capa_training_id FROM capas WHERE capa_number = 'CAPA-' || current_year || '-002';

    INSERT INTO capa_actions (capa_id, action_type, description, assigned_to, due_date, completed_date, organization_id, version, created_at, created_by, updated_at, updated_by)
    SELECT capa_label_id, 'CORRECTIVE', 'Relabel and segregate packaging material staging bins.', operator_user_id, now() + interval '7 days', null, org_id, 0, now() - interval '10 days', qa_user_id, now() - interval '2 days', qa_user_id
    WHERE NOT EXISTS (SELECT 1 FROM capa_actions WHERE capa_id = capa_label_id AND description = 'Relabel and segregate packaging material staging bins.');
    INSERT INTO capa_actions (capa_id, action_type, description, assigned_to, due_date, completed_date, organization_id, version, created_at, created_by, updated_at, updated_by)
    SELECT capa_label_id, 'PREVENTIVE', 'Train operators on barcode verification before batch start.', qa_user_id, now() + interval '14 days', null, org_id, 0, now() - interval '9 days', qa_user_id, now() - interval '2 days', qa_user_id
    WHERE NOT EXISTS (SELECT 1 FROM capa_actions WHERE capa_id = capa_label_id AND description = 'Train operators on barcode verification before batch start.');

    -- Deviations.
    INSERT INTO deviations (deviation_number, title, description, severity, status, root_cause, immediate_action, occurred_date, closed_date, submitted_by, organization_id, version, created_at, created_by, updated_at, updated_by)
    VALUES
      ('DEV-' || current_year || '-001', 'Temperature excursion in raw material store', 'Store reached 28 C for 45 minutes during power transfer.', 'MAJOR', 'UNDER_INVESTIGATION', null, 'Affected pallets placed on QA hold.', now() - interval '4 days', null, author_user_id, org_id, 1, now() - interval '4 days', operator_user_id, now() - interval '1 day', qa_user_id),
      ('DEV-' || current_year || '-002', 'Packaging count mismatch', 'Finished pack reconciliation showed 24-unit variance.', 'MINOR', 'PENDING_APPROVAL', 'Rejected cartons were counted twice during reconciliation.', 'Line stopped; QA recount completed.', now() - interval '15 days', null, author_user_id, org_id, 2, now() - interval '15 days', operator_user_id, now() - interval '2 days', author_user_id),
      ('DEV-' || current_year || '-003', 'Late line clearance documentation', 'Line clearance checklist completed after start-up.', 'MINOR', 'CLOSED', 'Supervisor was unavailable at planned start time.', 'Retrospective verification completed.', now() - interval '45 days', now() - interval '35 days', qa_user_id, org_id, 4, now() - interval '45 days', operator_user_id, now() - interval '35 days', qa_user_id)
    ON CONFLICT (deviation_number) DO UPDATE SET title = EXCLUDED.title, status = EXCLUDED.status, updated_at = now();

    -- Batch Records.
    INSERT INTO batch_records (batch_no, product_id, product_code, batch_size, unit, manufacturing_start_date, manufacturing_end_date, notes, status, submitted_by, released_by, released_at, organization_id, version, created_at, created_by, updated_at, updated_by)
    VALUES
      ('BATCH-' || current_year || '-001', product_tablet_id, 'PROD-' || current_year || '-001', 100000, 'UNIT', now() - interval '3 days', null, 'Compression in progress; blend yield within expected range.', 'IN_PROGRESS', operator_user_id, null, null, org_id, 1, now() - interval '3 days', operator_user_id, now() - interval '1 day', operator_user_id),
      ('BATCH-' || current_year || '-002', product_tablet_id, 'PROD-' || current_year || '-001', 80000, 'UNIT', now() - interval '12 days', now() - interval '9 days', 'QA review pending for reconciliation packet.', 'QA_REVIEW', qa_user_id, null, null, org_id, 2, now() - interval '12 days', operator_user_id, now() - interval '2 days', qa_user_id),
      ('BATCH-' || current_year || '-003', product_tablet_id, 'PROD-' || current_year || '-001', 95000, 'UNIT', now() - interval '45 days', now() - interval '42 days', 'Released demo batch.', 'RELEASED', qa_user_id, qa_user_id, now() - interval '38 days', org_id, 4, now() - interval '45 days', operator_user_id, now() - interval '38 days', qa_user_id),
      ('BATCH-' || current_year || '-004', product_syrup_id, 'PROD-' || current_year || '-002', 1200, 'L', now() - interval '7 days', now() - interval '6 days', 'Quarantined pending OOS investigation.', 'QUARANTINE', qa_user_id, null, null, org_id, 3, now() - interval '7 days', operator_user_id, now() - interval '1 day', qa_user_id)
    ON CONFLICT (batch_no) DO UPDATE SET notes = EXCLUDED.notes, status = EXCLUDED.status, updated_at = now();
    SELECT id INTO batch_tablet_id FROM batch_records WHERE batch_no = 'BATCH-' || current_year || '-001';

    INSERT INTO batch_materials_used (batch_record_id, material_id, material_code, lot_number, supplier, quantity_used, unit, created_at, created_by, organization_id)
    SELECT batch_tablet_id, material_api_id, 'MAT-' || current_year || '-001', 'API-DEMO-2406', 'Acme API Supplies', 125.5, 'KG', now() - interval '2 days', operator_user_id, org_id
    WHERE NOT EXISTS (SELECT 1 FROM batch_materials_used WHERE batch_record_id = batch_tablet_id AND lot_number = 'API-DEMO-2406');
    INSERT INTO batch_production_steps (batch_record_id, step_number, step_description, equipment_used, operator_id, start_time, end_time, parameters_recorded, anomalies_noted, created_at, created_by, organization_id)
    SELECT batch_tablet_id, 10, 'Blend API and excipients', 'Blender BL-02', operator_user_id, now() - interval '2 days', now() - interval '2 days' + interval '3 hours', 'Blend speed 18 rpm; endpoint met.', 'None', now() - interval '2 days', operator_user_id, org_id
    WHERE NOT EXISTS (SELECT 1 FROM batch_production_steps WHERE batch_record_id = batch_tablet_id AND step_number = 10);
    INSERT INTO batch_qc_results (batch_record_id, test_method, specification_limit, actual_result, test_date, test_status, test_lab, approved_by, created_at, created_by, organization_id)
    SELECT batch_tablet_id, 'Blend uniformity', 'RSD NMT 5.0%', 'RSD 2.4%', now() - interval '1 day', 'PASS', 'QC Lab', qa_user_id, now() - interval '1 day', qa_user_id, org_id
    WHERE NOT EXISTS (SELECT 1 FROM batch_qc_results WHERE batch_record_id = batch_tablet_id AND test_method = 'Blend uniformity');
    INSERT INTO batch_products_produced (batch_record_id, product_id, product_code, lot_number_assigned, quantity, unit, created_at, created_by, organization_id)
    SELECT batch_tablet_id, product_tablet_id, 'PROD-' || current_year || '-001', 'PT-DEMO-001', 98200, 'UNIT', now() - interval '1 day', operator_user_id, org_id
    WHERE NOT EXISTS (SELECT 1 FROM batch_products_produced WHERE batch_record_id = batch_tablet_id AND lot_number_assigned = 'PT-DEMO-001');

    -- Complaints.
    INSERT INTO complaints (complaint_no, product_id, complaint_description, source, severity, reported_date, reported_by, owner_id, status, submitted_by, closed_date, organization_id, version, created_at, created_by, updated_at, updated_by)
    VALUES
      ('COMPL-' || current_year || '-001', product_tablet_id, 'Customer reported chipped tablet in blister pocket.', 'CUSTOMER', 'MAJOR', now() - interval '6 days', 'Distributor QA', qa_user_id, 'UNDER_INVESTIGATION', qa_user_id, null, org_id, 2, now() - interval '6 days', qa_user_id, now() - interval '1 day', qa_user_id),
      ('COMPL-' || current_year || '-002', product_tablet_id, 'Internal complaint: carton print smudge observed during retention review.', 'INTERNAL', 'MINOR', now() - interval '21 days', 'Retention sample review', author_user_id, 'RESOLVED', author_user_id, null, org_id, 3, now() - interval '21 days', author_user_id, now() - interval '3 days', qa_user_id),
      ('COMPL-' || current_year || '-003', product_syrup_id, 'Customer reported leaking bottle cap.', 'CUSTOMER', 'CRITICAL', now() - interval '38 days', 'Pharmacy hotline', qa_user_id, 'CLOSED', qa_user_id, now() - interval '20 days', org_id, 5, now() - interval '38 days', qa_user_id, now() - interval '20 days', qa_user_id)
    ON CONFLICT (complaint_no) DO UPDATE SET complaint_description = EXCLUDED.complaint_description, status = EXCLUDED.status, updated_at = now();

    -- Audits.
    INSERT INTO audits (audit_no, audit_title, audit_type, audit_date, auditor_id, auditee_id, scope, status, submitted_by, completed_date, organization_id, version, created_at, created_by, updated_at, updated_by)
    VALUES
      ('AUD-' || current_year || '-001', 'Quarterly GMP self-inspection', 'INTERNAL', now() + interval '7 days', qa_user_id, operator_user_id, 'Manufacturing and warehouse GMP controls.', 'PLANNED', qa_user_id, null, org_id, 0, now() - interval '3 days', qa_user_id, now() - interval '3 days', qa_user_id),
      ('AUD-' || current_year || '-002', 'Packaging supplier surveillance audit', 'SUPPLIER', now() - interval '10 days', qa_user_id, null, 'Supplier print controls and COA review.', 'COMPLETED', qa_user_id, now() - interval '8 days', org_id, 3, now() - interval '25 days', qa_user_id, now() - interval '8 days', qa_user_id)
    ON CONFLICT (audit_no) DO UPDATE SET audit_title = EXCLUDED.audit_title, status = EXCLUDED.status, updated_at = now();
    SELECT id INTO audit_gmp_id FROM audits WHERE audit_no = 'AUD-' || current_year || '-002';

    INSERT INTO audit_findings (audit_id, finding_number, description, area, severity, evidence, root_cause, corrective_action_required, created_at, created_by, organization_id)
    SELECT audit_gmp_id, 1, 'Supplier COA traceability evidence was incomplete for one reviewed lot.', 'Supplier Quality', 'MAJOR', 'Audit worksheet item SQ-04.', 'Checklist did not require COA reviewer initials.', true, now() - interval '8 days', qa_user_id, org_id
    WHERE NOT EXISTS (SELECT 1 FROM audit_findings WHERE audit_id = audit_gmp_id AND finding_number = 1);

    -- Risk Management.
    INSERT INTO risks (risk_no, title, description, category, potential_impact, likelihood, risk_score, status, owner_id, submitted_by, accepted_by, accepted_date, closed_date, organization_id, version, created_at, created_by, updated_at, updated_by)
    VALUES
      ('RISK-' || current_year || '-001', 'Packaging component mix-up', 'Similar packaging components can be staged on the same line.', 'PROCESS', 'Incorrect label or leaflet may reach patient.', 4, 16, 'MITIGATED', qa_user_id, qa_user_id, null, null, null, org_id, 2, now() - interval '30 days', qa_user_id, now() - interval '4 days', qa_user_id),
      ('RISK-' || current_year || '-002', 'Cold chain monitor failure', 'Warehouse logger battery failure may mask excursions.', 'EQUIPMENT', 'Delayed detection of temperature excursions.', 3, 9, 'IDENTIFIED', qa_user_id, author_user_id, null, null, null, org_id, 0, now() - interval '2 days', author_user_id, now() - interval '2 days', author_user_id),
      ('RISK-' || current_year || '-003', 'Alternate API supplier onboarding', 'New supplier requires continued performance monitoring.', 'PRODUCT', 'Quality variation if controls are ineffective.', 2, 6, 'ACCEPTED', qa_user_id, qa_user_id, qa_user_id, now() - interval '5 days', null, org_id, 3, now() - interval '42 days', qa_user_id, now() - interval '5 days', qa_user_id)
