    SELECT risk_mixup_id, 'Barcode verification before line clearance approval.', 'PROCESS', qa_user_id, now() - interval '8 days', 'Review three completed batch records.', now() - interval '18 days', qa_user_id, org_id
    WHERE NOT EXISTS (SELECT 1 FROM risk_mitigation WHERE risk_id = risk_mixup_id AND control_description = 'Barcode verification before line clearance approval.');
    INSERT INTO risk_control_effectiveness (risk_id, verification_date, verified_by, residual_risk_acceptable, evidence, created_at, created_by, organization_id)
