      ('SUP-' || current_year || '-002', 'PrintPack Ltd', 'PACKAGING', 'James Otieno', 'quality@printpack.example', '+254700100201', 'Athi River, Kenya', 'CONDITIONAL', now() - interval '20 days', qa_user_id, org_id, 1, now() - interval '45 days', qa_user_id, now() - interval '3 days', qa_user_id),
