    INSERT INTO audit_logs (record_type, record_id, action, field_name, old_value, new_value, reason_for_change, user_id, user_full_name, utc_timestamp, ip_address, user_agent, organization_id)
    SELECT 'DemoSeed', org_id::text, 'CREATE', null, null, 'Seeded representative demo dataset for all modules', 'Local demo setup', admin_id, 'Demo System', now(), '127.0.0.1', 'Liquibase demo seed', org_id
    WHERE NOT EXISTS (SELECT 1 FROM audit_logs WHERE record_type = 'DemoSeed' AND record_id = org_id::text);

    -- Keep sequence generators ahead of seeded record numbers.
    INSERT INTO record_sequences (module_code, year, prefix, current_value, padding, format, created_at, updated_at, version, organization_id)
    SELECT code, current_year, code, 10, 3, '{prefix}-{year}-{seq}', now(), now(), 0, org_id
    FROM unnest(ARRAY['SOP','FORM','WI','CC','CAPA','DEV','PROD','MAT','BATCH','COMPL','AUD','RISK','SUP','TRN','EQUIP','OOS','NC','MR']) AS code
    ON CONFLICT (module_code, year) DO UPDATE SET current_value = GREATEST(record_sequences.current_value, 10), updated_at = now();
END $$;
